text:
0.2 Efekty uczenia
Po przejściu materiału potrafisz:

zaimportować i przygotować dane do wykresu;
rozpoznać, kiedy użyć wykresu punktowego (scatter plot), liniowego (line chart), słupkowego (bar chart), mapy ciepła (heatmap) albo małych wielokrotności (small multiples);
budować wykres warstwowo przez ggplot(), aes(), geom_*(), skale, podział na panele (faceting) i motywy;
pisać wykresy z dobrymi etykietami, jednostkami, podpisami i paletami przyjaznymi dla osób z zaburzeniami widzenia barw;
formatować znaczniki osi (ticks), wartości na osiach, tytuły (titles) i etykiety (labels);
eksportować wykresy w jakości do slajdów, raportu i publikacji internetowej;
używać animacji, gdy pokazuje proces albo zmianę w czasie;
przygotować końcowy mini-projekt analityczny w Quarto.

3.1 Dane i mapowania estetyczne (aesthetics)
ggplot2 opiera się na prostej idei: wykres składamy z danych, mapowań, geometrii, skal, statystyk, podziału na panele (faceting) i motywu. Dzięki temu zamiast pamiętać setki funkcji, uczymy się jednego spójnego języka.
mpg_local &lt;- readr::read_csv(
  here("datasets", "mpg.csv"),
  show_col_types = FALSE
) |&gt;
  mutate(
    cylinders = factor(cylinders),
    origin = factor(
      recode(origin, usa = "USA", europe = "Europa", japan = "Japonia"),
      levels = c("USA", "Europa", "Japonia")
    )
  )

insurance &lt;- readr::read_csv(
  here("datasets", "insurance_premiums.csv"),
  show_col_types = FALSE
) |&gt;
  janitor::clean_names() |&gt;
  mutate(
    region = factor(
      recode(
        region,
        Midwest = "Środkowy Zachód",
        Northeast = "Północny Wschód",
        South = "Południe",
        West = "Zachód"
      ),
      levels = c("Środkowy Zachód", "Północny Wschód", "Południe", "Zachód")
    )
  )

mpg_local |&gt;
  select(mpg, cylinders, displacement, horsepower, weight, origin) |&gt;
  slice_head(n = 6)
mpg_local |&gt;
  ggplot(aes(x = weight, y = mpg, colour = cylinders)) +
  geom_point(alpha = 0.75, size = 2.2) +
  scale_colour_course_d(name = "Liczba cylindrów") +
  labs(
    title = "Cięższe auta spalają więcej paliwa",
    subtitle = "Kolor koduje liczbę cylindrów, czyli dodatkowy wymiar danych",
    x = "Masa auta",
    y = "Efektywność paliwowa (mpg)",
    caption = "Źródło: datasets/mpg.csv"
  )







Rysunek 3.1: Zależność masy samochodu i spalania.

6.2 Porównanie serii przez indeks
Gdy serie mają różne poziomy, często lepiej pokazać indeks od wspólnego punktu startu niż surową cenę.

stocks &lt;- readr::read_csv(here("datasets", "stocks_cleaned.csv"), show_col_types = FALSE) |&gt;
  janitor::clean_names() |&gt;
  select(-any_of("x1")) |&gt;
  mutate(date = lubridate::ymd(date))

stocks |&gt;
  filter(name %in% c("AAPL", "AMZN", "MSFT")) |&gt;
  arrange(name, date) |&gt;
  group_by(name) |&gt;
  mutate(close_index = close / first(close) * 100) |&gt;
  ungroup() |&gt;
  ggplot(aes(x = date, y = close_index, colour = name)) +
  geom_line(linewidth = 0.75) +
  scale_colour_course_d(name = "Spółka") +
  labs(
    title = "Indeks 100 ułatwia porównanie serii o różnych poziomach",
    x = NULL,
    y = "Cena zamknięcia, indeks = 100",
    caption = "Źródło: datasets/stocks_cleaned.csv"
  )







Rysunek 6.2: Indeks cen zamknięcia dla wybranych spółek.

6.3 Agregacja przed wykresem liniowym

bike_month &lt;- readr::read_csv(here("datasets", "bike_share.csv"), show_col_types = FALSE) |&gt;
  janitor::clean_names() |&gt;
  mutate(date = lubridate::ymd(dteday), month = floor_date(date, "month")) |&gt;
  group_by(month) |&gt;
  summarise(avg_rentals = mean(total_rentals), .groups = "drop")

bike_month |&gt;
  ggplot(aes(x = month, y = avg_rentals)) +
  geom_line(colour = "#009E73", linewidth = 0.9) +
  geom_point(colour = "#009E73", size = 1.7) +
  labs(
    title = "Agregacja powinna wynikać z pytania, nie z wygody",
    x = NULL,
    y = "Średnia dzienna liczba wypożyczeń",
    caption = "Źródło: datasets/bike_share.csv"
  )







Rysunek 6.3: Średnia dzienna liczba wypożyczeń rowerów według miesiąca.

11.3 Paleta jakościowa dla kilku kategorii
Kiedy wszystkie kategorie są równie ważne, używamy palety jakościowej. Kolory powinny być od siebie wyraźnie różne, ale nie muszą tworzyć skali od jasnego do ciemnego.

medals &lt;- readr::read_csv(
  here("datasets", "medals_by_country_2016.csv"),
  show_col_types = FALSE
) |&gt;
  rename(country = `...1`) |&gt;
  pivot_longer(
    cols = c(Bronze, Gold, Silver),
    names_to = "medal",
    values_to = "count"
  ) |&gt;
  mutate(
    medal = factor(
      recode(medal, Gold = "Złoto", Silver = "Srebro", Bronze = "Brąz"),
      levels = c("Złoto", "Srebro", "Brąz")
    ),
    country = forcats::fct_reorder(country, count, .fun = sum)
  )

medals |&gt;
  ggplot(aes(x = count, y = country, fill = medal)) +
  geom_col(width = 0.72) +
  scale_fill_manual(
    values = c(Złoto = "#D6A21E", Srebro = "#9AA3AA", Brąz = "#A97142"),
    name = "Medal"
  ) +
  labs(
    title = "Paleta ręczna jest dobra, gdy kolor ma oczywiste znaczenie",
    x = "Liczba medali",
    y = "Kraj",
    caption = "Źródło: datasets/medals_by_country_2016.csv"
  )







Rysunek 11.3: Paleta ręczna dla typów medali.

13.3 Bezpośrednie etykiety serii
Gdy na wykresie jest kilka linii, bezpośrednie etykiety (direct labels) często są czytelniejsze niż legenda. Etykieta przy końcu linii skraca drogę wzroku między kolorem a nazwą serii.

stocks_index &lt;- readr::read_csv(here("datasets", "stocks_cleaned.csv"), show_col_types = FALSE) |&gt;
  janitor::clean_names() |&gt;
  select(-any_of("x1")) |&gt;
  filter(name %in% c("AAPL", "AMZN", "MSFT")) |&gt;
  arrange(name, date) |&gt;
  group_by(name) |&gt;
  mutate(close_index = close / first(close) * 100) |&gt;
  ungroup()

stock_ends &lt;- stocks_index |&gt;
  group_by(name) |&gt;
  slice_max(date, n = 1, with_ties = FALSE) |&gt;
  ungroup()

stocks_index |&gt;
  ggplot(aes(x = date, y = close_index, colour = name)) +
  geom_line(linewidth = 0.8) +
  ggrepel::geom_text_repel(
    data = stock_ends,
    aes(label = name),
    nudge_x = 80,
    direction = "y",
    hjust = 0,
    segment.color = NA,
    show.legend = FALSE
  ) +
  scale_colour_course_d(guide = "none") +
  scale_y_continuous(labels = scales::label_number(suffix = " pkt")) +
  coord_cartesian(clip = "off") +
  labs(
    title = "Etykiety przy liniach mogą zastąpić legendę",
    subtitle = "Cena zamknięcia przeliczona do indeksu 100 w pierwszym dniu obserwacji",
    x = NULL,
    y = "Indeks ceny zamknięcia",
    caption = "Źródło: datasets/stocks_cleaned.csv"
  ) +
  theme(plot.margin = margin(8, 48, 8, 8))







Rysunek 13.3: Indeks cen akcji z etykietami bezpośrednimi.

13.5 Podpis i tekst alternatywny
Podpis (caption) podaje źródło, ograniczenia albo sposób obliczenia. Tekst alternatywny (alt text) opisuje najważniejszą informację z wykresu osobie, która nie widzi obrazu. W Quarto tekst alternatywny dodajemy przez opcję fig-alt.

medals_total &lt;- readr::read_csv(
  here("datasets", "medals_by_country_2016.csv"),
  show_col_types = FALSE
) |&gt;
  rename(country = `...1`) |&gt;
  mutate(total = Bronze + Gold + Silver) |&gt;
  slice_max(total, n = 8) |&gt;
  mutate(country = forcats::fct_reorder(country, total))

medals_total |&gt;
  ggplot(aes(x = total, y = country)) +
  geom_col(fill = "#0072B2", width = 0.72) +
  labs(
    title = "Największe kraje medalowe warto pokazać jako ranking",
    x = "Liczba medali",
    y = NULL,
    caption = "Źródło: datasets/medals_by_country_2016.csv; pokazano 8 krajów z największą liczbą medali"
  )







Rysunek 13.5: Przykład wykresu z podpisem i tekstem alternatywnym zapisanym w opcji chunku.

jednego pytania głównego;
krótkiego opisu danych i ograniczeń;
dwóch wykresów eksploracyjnych;
jednego wykresu finalnego dopracowanego pod odbiorcę;
krótkiej interpretacji: co wiemy, czego nie wiemy, co sprawdzić dalej.

15.1 Przetwarzanie danych
W tej części stworzymy wykres typu “dumbbell” (lub “slope chart”). Znakomicie nadaje się on do pokazywania zmiany wartości między dwoma punktami w czasie dla wielu kategorii (w naszym przypadku - europejskich państw).
Wykorzystamy zbiór danych dotyczący procentu gospodarstw domowych z dostępem do internetu.
Na początku wczytamy plik isoc_r_iacc_h_page_linear_2_0.csv. Następnie wyciągniemy kody państw i przefiltrujemy dane, zostawiając jedynie lata 2006 i 2023, tak jak na wzorze.
df_raw &lt;- read_csv(here("datasets", "isoc_r_iacc_h_page_linear_2_0.csv")) |&gt; 
  clean_names()

df_clean &lt;- df_raw |&gt; 
  select(
    geo = geo_geopolitical_entity_reporting, 
    year = time_period_time, 
    value = obs_value_observation_value
  ) |&gt; 
  # Wyciągamy dwuliterowy kod i nazwę państwa (np. z "AT: Austria")
  separate(geo, into = c("code", "country"), sep = ": ") |&gt; 
  # Odrzucamy regiony - zostawiamy tylko dwuliterowe kody (państwa)
  filter(nchar(code) == 2) |&gt; 
  # Odrzucamy unijne agregaty zbiorcze, np. EA (Strefa Euro), EU
  filter(!code %in% c("EA", "EU")) |&gt; 
  # Zostawiamy interesujące nas lata
  filter(year %in% c(2006, 2023)) |&gt; 
  # Zostawiamy tylko te kraje, które mają odnotowane dane w obu latach
  group_by(country) |&gt; 
  filter(n() == 2) |&gt; 
  ungroup() |&gt; 
  # Sortujemy państwa rosnąco według wyniku z 2023, aby na górze były te z najwyższym
  mutate(
    year = as.factor(year),
    country = fct_reorder(country, value, .fun = max)
  )

# Szukamy "najwyższego" państwa na wykresie, aby nad nim narysować etykiety "2006" i "2023"
top_country &lt;- df_clean |&gt; 
  filter(value == max(value)) |&gt; 
  pull(country) |&gt; 
  as.character()

17.1 Przygotowanie danych
Wizualizacja nie jest konkursem na najbardziej efektowny kształt. Jeżeli odbiorca ma porównać wielkości, najbezpieczniej jest dać mu wspólną oś i długość, a nie kąt i pole. Na prostym przykładzie z medalami olimpijskimi zobaczymy, dlaczego wykres kołowy szybko traci czytelność i jak naprawić go rankingiem słupkowym.
Skorzystamy z pliku medals_by_country_2016.csv. Policzymy łączną liczbę medali, zostawimy sześć krajów z najwyższym wynikiem i połączymy resztę w kategorię Pozostałe. To dokładnie ten moment, w którym pie chart wydaje się kuszący.
medals &lt;- readr::read_csv(
  here("datasets", "medals_by_country_2016.csv"),
  show_col_types = FALSE
) |&gt;
  rename(country = `...1`) |&gt;
  mutate(total = Bronze + Gold + Silver) |&gt;
  arrange(desc(total))

medals_pie &lt;- medals |&gt;
  slice_head(n = 6) |&gt;
  bind_rows(
    medals |&gt;
      slice(-(1:6)) |&gt;
      summarise(country = "Pozostałe", total = sum(total))
  ) |&gt;
  mutate(
    share = total / sum(total),
    label = paste0(country, "\n", scales::percent(share, accuracy = 1))
  )

medals_bar &lt;- medals_pie |&gt;
  mutate(country = forcats::fct_reorder(country, total))

18.1 Przygotowanie danych
Na osi czasu najłatwiej przesadzić z liczbą komunikatów. Kilka kolorowych linii na jednym wykresie szybko zamienia się w spaghetti chart, w którym legenda staje się dodatkową przeszkodą. Celem nie jest pokazanie wszystkiego naraz, tylko pokierowanie wzrokiem odbiorcy.
Wybierzemy siedem spółek technologicznych z stocks_cleaned.csv i przeliczymy ich ceny zamknięcia do wspólnego indeksu startowego równego 100. Dzięki temu nie porównujemy poziomów cen, tylko tempo wzrostu od tego samego punktu.
tech_stocks &lt;- readr::read_csv(
  here("datasets", "stocks_cleaned.csv"),
  show_col_types = FALSE
) |&gt;
  janitor::clean_names() |&gt;
  select(-any_of("x1")) |&gt;
  filter(name %in% c("AAPL", "AMZN", "FB", "GOOG", "MSFT", "NFLX", "NVDA")) |&gt;
  arrange(name, date) |&gt;
  group_by(name) |&gt;
  mutate(close_index = close / first(close) * 100) |&gt;
  ungroup() |&gt;
  mutate(
    focus = if_else(name == "NVDA", "NVDA", "Pozostałe spółki")
  )

highlight_end &lt;- tech_stocks |&gt;
  filter(name == "NVDA") |&gt;
  slice_max(date, n = 1, with_ties = FALSE) |&gt;
  mutate(
    label_date = date + 120,
    label_text = paste0("NVDA: ", round(close_index), " pkt")
  )

20.1 Przygotowanie danych
Średnia jest wygodna, ale potrafi być zdradliwa. Jeżeli pokażemy tylko jeden słupek z przeciętną wartością, ukryjemy rozrzut, asymetrię i obserwacje odstające. Dlatego przed interpretacją warto zobaczyć cały rozkład.
W pliku student-alcohol-consumption.csv mamy m.in. ocenę końcową G3 oraz poziom weekendowego spożycia alkoholu Walc w skali od 1 do 5. To dobry materiał do pokazania, że podobne średnie nie muszą oznaczać podobnych rozkładów.
students &lt;- readr::read_csv(
  here("datasets", "student-alcohol-consumption.csv"),
  show_col_types = FALSE
) |&gt;
  janitor::clean_names() |&gt;
  transmute(
    walc = factor(
      walc,
      levels = 1:5,
      labels = c("1 niskie", "2", "3", "4", "5 wysokie")
    ),
    g3
  ) |&gt;
  drop_na(walc, g3)

mean_scores &lt;- students |&gt;
  group_by(walc) |&gt;
  summarise(mean_g3 = mean(g3), .groups = "drop")

22.1 Przygotowanie danych
Wizualizacja zaczyna się tam, gdzie przestajemy traktować tabelę jako cel sam w sobie. Surowe rekordy są jeszcze tylko zapisem zdarzeń. Dopiero wybór osi, koloru i układu zamienia je w kod, który nasz układ wzrokowy potrafi czytać niemal natychmiast.
Na zbiorze bakery.csv pokażemy prostą drogę: od wielu pojedynczych transakcji do syntetycznego obrazu rytmu sprzedaży. Interesuje nas łączna sprzedaż według typu dnia i pory dnia.
bakery_grid &lt;- readr::read_csv(
  here("datasets", "bakery.csv"),
  show_col_types = FALSE
) |&gt;
  janitor::clean_names() |&gt;
  count(day_type, day_time, wt = sales, name = "sales_total") |&gt;
  mutate(
    day_type = factor(day_type, levels = c("Weekday", "Weekend")),
    day_time = factor(day_time, levels = c("Morning", "Afternoon", "Evening", "Night")),
    sales_label = scales::label_number(accuracy = 1, big.mark = " ")(sales_total)
  )

23.1 Przygotowanie danych
W rękach analityka wykres może pełnić dwie role jednocześnie: być narzędziem badawczym i narzędziem perswazji. John Snow używał mapy, by zawęzić źródło problemu. Florence Nightingale używała koloru i pola, by wymusić reakcję polityczną.
Nie mamy tu danych epidemiologicznych, ale mamy dwa zbiory pogodowe: seattle_weather.csv i austin_weather.csv. Zestawimy miesięczne normy opadów, żeby zobaczyć, jak ten sam fakt można pokazać bardziej neutralnie albo bardziej perswazyjnie.
weather_compare &lt;- bind_rows(
  readr::read_csv(here("datasets", "seattle_weather.csv"), show_col_types = FALSE) |&gt;
    janitor::clean_names() |&gt;
    transmute(
      city = "Seattle",
      month = as.integer(date),
      precipitation = mly_prcp_normal
    ),
  readr::read_csv(here("datasets", "austin_weather.csv"), show_col_types = FALSE) |&gt;
    janitor::clean_names() |&gt;
    transmute(
      city = "Austin",
      month = as.integer(date),
      precipitation = mly_prcp_normal
    )
) |&gt;
  mutate(
    month_label = factor(month.abb[month], levels = month.abb),
    precipitation_area = sqrt(precipitation)
  )

24.1 Przygotowanie danych
Gęsty wykres nie musi być zły. Minard udowodnił, że nawet wiele wymiarów naraz może pozostać czytelne, jeśli każdy kanał wizualny ma jedną pracę i nie konkuruje z innymi bez potrzeby.
Na danych z summer2016.csv wybierzemy sześć sportów o wyraźnie różnych profilach fizycznych. To dobry materiał do wykresu wielowymiarowego: wysokość i masa na osiach, wiek jako rozmiar punktu, a płeć jako kolor.
selected_sports &lt;- c("Athletics", "Basketball", "Gymnastics", "Rowing", "Swimming", "Volleyball")

olympians &lt;- readr::read_csv(
  here("datasets", "summer2016.csv"),
  show_col_types = FALSE
) |&gt;
  janitor::clean_names() |&gt;
  filter(
    sport %in% selected_sports,
    !is.na(height),
    !is.na(weight),
    !is.na(age)
  ) |&gt;
  mutate(
    sex = recode(sex, F = "Kobiety", M = "Mężczyźni"),
    sport = factor(sport, levels = selected_sports)
  )

26.1 Przygotowanie danych
Storytelling nie oznacza dopisywania anegdoty do gotowego wykresu. To projektowanie całego przepływu uwagi: od kontekstu, przez dowód, po działanie. Dobrze widać to na danych o gościach programu The Daily Show.
Najpierw policzymy udziały najważniejszych grup gości w czasie. Interesuje nas szczególnie przejście od dominacji aktorów do silniejszej obecności mediów i polityki.
daily_show &lt;- readr::read_csv(
  here("datasets", "daily_show_guests_cleaned.csv"),
  show_col_types = FALSE
) |&gt;
  janitor::clean_names() |&gt;
  mutate(group = replace_na(group, "Brak kategorii"))

top_groups &lt;- daily_show |&gt;
  count(group, sort = TRUE) |&gt;
  slice_head(n = 6) |&gt;
  pull(group)

daily_top &lt;- daily_show |&gt;
  filter(group %in% top_groups) |&gt;
  count(year, group) |&gt;
  group_by(year) |&gt;
  mutate(share = n / sum(n)) |&gt;
  ungroup()

daily_story &lt;- daily_show |&gt;
  count(year, group) |&gt;
  group_by(year) |&gt;
  mutate(share = n / sum(n)) |&gt;
  ungroup() |&gt;
  mutate(
    focus = case_when(
      group %in% c("Media", "Politician", "Government", "Political Aide") ~ "Media i polityka",
      group == "Acting" ~ "Aktorzy",
      TRUE ~ "Pozostałe"
    )
  ) |&gt;
  group_by(year, focus) |&gt;
  summarise(share = sum(share), .groups = "drop")

crossover &lt;- daily_story |&gt;
  select(year, focus, share) |&gt;
  pivot_wider(names_from = focus, values_from = share) |&gt;
  filter(`Media i polityka` &gt; Aktorzy) |&gt;
  slice_head(n = 1)
